{
  "type": "object",
  "properties": {
    "q": {
      "type": "string",
      "description": "Марка/модель латиницей как в каталоге (Audi, BMW, Q2). Русские марки переводи в латиницу. Без бюджета"
    },
    "max_total_rub": {
      "type": "number",
      "description": "Макс. цена под ключ в рублях: 3000000 для 3 млн, 2500000 для 2.5 млн"
    },
    "min_total_rub": {
      "type": "number",
      "description": "Мин. цена под ключ в рублях (необязательно)"
    }
  }
}

parameters.jsCode:
const settings = $('Настройки workflow').first().json;
const webOrigin = String(settings.webOrigin || 'https://avtovozom.com').replace(/\/$/, '');
const input = typeof query === 'string' ? JSON.parse(query) : { ...query };

function extractSearchParams(raw) {
  let q = String(raw.q || '').trim();
  let maxTotalRub = raw.max_total_rub != null && raw.max_total_rub !== '' ? Number(raw.max_total_rub) : null;
  let minTotalRub = raw.min_total_rub != null && raw.min_total_rub !== '' ? Number(raw.min_total_rub) : null;
  const src = q;
  const mlnRe = /(?:до\s*)?(\d+(?:[.,]\d+)?)\s*млн/gi;
  let m;
  while ((m = mlnRe.exec(src)) !== null) {
    if (!Number.isFinite(maxTotalRub) || maxTotalRub <= 0) {
      maxTotalRub = Math.round(parseFloat(m[1].replace(',', '.')) * 1000000);
    }
  }
  q = q.replace(/до\s*\d+(?:[.,]\d+)?\s*млн/gi, ' ')
    .replace(/\d+(?:[.,]\d+)?\s*млн/gi, ' ')
    .replace(/до\s*\d[\d\s]{5,}/gi, ' ')
    .replace(/(?:₽|руб(?:\.?|лей)?)/gi, ' ');
  q = q.replace(/\b(ищу|нужен[ао]?|хочу|подобрать|найти|авто|машин[ауы]?|покажи|есть ли)\b/giu, ' ')
    .replace(/\s+/g, ' ').trim();
  q = latinizeBrandQuery(q);
  return { q, maxTotalRub, minTotalRub };
}

const BRAND_ALIASES = [
  ['мерседес-бенц', 'Mercedes-Benz'], ['мерседес', 'Mercedes-Benz'], ['мерс', 'Mercedes-Benz'],
  ['фольксваген', 'Volkswagen'], ['фольцваген', 'Volkswagen'], ['фолькс', 'Volkswagen'],
  ['ленд ровер', 'Land Rover'], ['линк ко', 'Lynk & Co'], ['линк энд ко', 'Lynk & Co'],
  ['ли авто', 'Li Auto'], ['ли-авто', 'Li Auto'], ['гак трумпчи', 'GAC Trumpchi'],
  ['альфа ромео', 'Alfa Romeo'], ['грейт вол', 'GWM'], ['ауди', 'Audi'], ['бмв', 'BMW'],
  ['тойота', 'Toyota'], ['мазда', 'Mazda'], ['ниссан', 'Nissan'], ['хонда', 'Honda'],
  ['форд', 'Ford'], ['лексус', 'Lexus'], ['хёндай', 'Hyundai'], ['хендай', 'Hyundai'],
  ['хондай', 'Hyundai'], ['хендэ', 'Hyundai'], ['киа', 'Kia'], ['кия', 'Kia'],
  ['вольво', 'Volvo'], ['порше', 'Porsche'], ['рено', 'Renault'], ['пежо', 'Peugeot'],
  ['ситроен', 'Citroën'], ['ситроён', 'Citroën'], ['шкода', 'Škoda'], ['опель', 'Opel'],
  ['субару', 'Subaru'], ['сузуки', 'Suzuki'], ['мицубиси', 'Mitsubishi'], ['ягуар', 'Jaguar'],
  ['инфинити', 'Infiniti'], ['джип', 'Jeep'], ['мини', 'MINI'], ['чери', 'Chery'],
  ['бид', 'BYD'], ['би вай ди', 'BYD'], ['джили', 'Geely'], ['гели', 'Geely'],
  ['геели', 'Geely'], ['хавал', 'Haval'], ['чанган', 'Changan'], ['хонгци', 'Hongqi'],
  ['хончи', 'Hongqi'], ['зикр', 'Zeekr'], ['зикер', 'Zeekr'], ['нио', 'NIO'],
  ['войя', 'Voyah'], ['воя', 'Voyah'], ['танк', 'Tank'], ['вей', 'WEY'], ['эксид', 'Exeed'],
  ['омода', 'Omoda'], ['джетур', 'Jetour'], ['воях', 'Voyah'],
];

function latinizeBrandQuery(text) {
  let out = String(text || '');
  const sorted = BRAND_ALIASES.slice().sort((a, b) => b[0].length - a[0].length);
  for (const [alias, latin] of sorted) {
    const re = new RegExp(alias.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'), 'giu');
    out = out.replace(re, latin);
  }
  return out.replace(/\s+/g, ' ').trim();
}

const parsed = extractSearchParams(input);
let q = parsed.q;
let maxTotalRub = parsed.maxTotalRub;
let minTotalRub = parsed.minTotalRub;
if (!q && !(Number.isFinite(maxTotalRub) && maxTotalRub > 0)) {
  return JSON.stringify({ error: 'Нужен q (марка/модель) и/или max_total_rub' });
}
const base = settings.apiBaseUrl.replace(/\/$/, '');
const fetchLimit = String(settings.searchCarsFetchLimit || '100');
const outLimit = Math.max(1, Number(settings.searchCarsLimit || '5') || 5);
const params = [];
function addParam(k, v) { params.push(encodeURIComponent(k) + '=' + encodeURIComponent(String(v))); }
if (q) addParam('q', q);
addParam('limit', fetchLimit);
addParam('photo_limit', '1');
if (Number.isFinite(maxTotalRub) && maxTotalRub > 0) addParam('sort', 'price_asc');
const url = base + '/cars?' + params.join('&');
try {
  const text = await this.helpers.httpRequest({ method: 'GET', url, json: false });
  const raw = typeof text === 'string' ? text : JSON.stringify(text);
  let data;
  try { data = JSON.parse(raw); } catch { return raw; }
  if (!Array.isArray(data.items)) return raw;
  let items = data.items.map((car) => ({
    id: car.id,
    title: car.title,
    brand: car.brand,
    model: car.model,
    year: car.year,
    mileage_km: car.mileage_km,
    price_cny: car.price_cny,
    estimated_total_rub: car.estimated_total_rub,
    listing_url: webOrigin + '/cars/' + car.id,
  }));
  if (Number.isFinite(maxTotalRub) && maxTotalRub > 0) {
    items = items.filter((car) => car.estimated_total_rub != null && car.estimated_total_rub <= maxTotalRub);
  }
  if (Number.isFinite(minTotalRub) && minTotalRub > 0) {
    items = items.filter((car) => car.estimated_total_rub != null && car.estimated_total_rub >= minTotalRub);
  }
  const totalMatched = items.length;
  items = items.slice(0, outLimit);
  return JSON.stringify({
    query_used: { q: q || null, max_total_rub: Number.isFinite(maxTotalRub) ? maxTotalRub : null },
    total_catalog: data.total,
    total_matched: totalMatched,
    items,
  });
} catch (error) {
  const status = error.statusCode ?? error.httpCode ?? error.response?.statusCode ?? '?';
  const body = String(error.response?.body || error.description || error.message || '').slice(0, 800);
  return JSON.stringify({ error: 'HTTP ' + status, body });
}

const settings = $('Настройки workflow').first().json;
const webOrigin = String(settings.webOrigin || 'https://avtovozom.com').replace(/\/$/, '');
const input = typeof query === 'string' ? JSON.parse(query) : { ...query };
const listing_id = String(input.listing_id || '').replace(/\D/g, '');
if (!listing_id) return JSON.stringify({ error: 'Нужен listing_id' });
const base = settings.apiBaseUrl.replace(/\/$/, '');
const url = base + '/cars/' + listing_id;
try {
  const text = await this.helpers.httpRequest({ method: 'GET', url, json: false });
  const raw = typeof text === 'string' ? text : JSON.stringify(text);
  let car;
  try { car = JSON.parse(raw); } catch { return raw; }
  if (car && car.id) car.listing_url = webOrigin + '/cars/' + car.id;
  return JSON.stringify(car);
} catch (error) {
  const status = error.statusCode ?? error.httpCode ?? error.response?.statusCode ?? '?';
  const body = String(error.response?.body || error.description || error.message || '').slice(0, 800);
  return JSON.stringify({ error: 'HTTP ' + status, body });
}

const settings = $('Настройки workflow').first().json;
const base = settings.apiBaseUrl.replace(/\/$/, '');
const url = base + '/faq';
try {
  const text = await this.helpers.httpRequest({ method: 'GET', url, json: false });
  return typeof text === 'string' ? text : JSON.stringify(text);
} catch (error) {
  const status = error.statusCode ?? error.httpCode ?? '?';
  const body = String(error.description || error.message || '').slice(0, 800);
  return JSON.stringify({ error: 'HTTP ' + status, body });
}

