}

parameters.jsCode:
const settings = $('Настройки workflow').first().json;
let ctx = {};
try { ctx = $('Контекст чата').first().json; } catch (e) { ctx = {}; }
const input = typeof query === 'string' ? JSON.parse(query) : { ...query };
const secret = String(settings.backendApiSecret || '').trim();
if (!secret || secret.includes('ЗАМЕНИТЕ')) {
  return JSON.stringify({ error: 'config', body: 'backendApiSecret не настроен в узле «Настройки workflow»' });
}
const user_name = String(input.user_name || ctx.firstName || 'Клиент').trim();
const user_contact = String(input.user_contact || '').trim();
const comment = String(input.comment || '').trim();
if (!user_contact) {
  return JSON.stringify({ error: 'Нужен user_contact (телефон или email)' });
}
if (comment.length < 3) {
  return JSON.stringify({ error: 'Нужен comment — описание авто (минимум 3 символа)' });
}
const payload = {
  user_name,
  user_contact,
  comment,
  telegram_chat_id: String(ctx.chatId || ''),
  telegram_username: String(ctx.username || ''),
};
const rawCarId = input.car_id;
if (rawCarId !== null && rawCarId !== undefined && String(rawCarId).trim() !== '') {
  const n = Number(String(rawCarId).replace(/\D/g, ''));
  if (Number.isFinite(n) && n > 0) payload.car_id = n;
}
const url = settings.apiBaseUrl.replace(/\/$/, '') + '/integrations/n8n/bot/create-request';
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url,
    headers: {
      'Content-Type': 'application/json',
      'X-N8N-Webhook-Secret': secret,
    },
    body: JSON.stringify(payload),
    json: false,
    returnFullResponse: true,
    ignoreHttpStatusErrors: true,
  });
  const status = resp.statusCode || resp.status || 0;
  const rawBody = resp.body ?? resp.data ?? '';
  const text = typeof rawBody === 'string' ? rawBody : JSON.stringify(rawBody);
  if (status < 200 || status >= 300) {
    return JSON.stringify({ error: 'HTTP ' + status, body: text.slice(0, 500) });
  }
  let result;
  try { result = JSON.parse(text); } catch { result = null; }
  if (result && result.ok === true && result.request_id) {
    return JSON.stringify({ ok: true, request_id: result.request_id, message: 'Заявка #' + result.request_id + ' принята' });
  }
  return JSON.stringify({ error: 'unexpected_response', body: text.slice(0, 500) });
} catch (error) {
  const status = error.statusCode ?? error.httpCode ?? error.response?.statusCode ?? '?';
  const body = String(error.response?.body || error.description || error.message || '').slice(0, 500);
  return JSON.stringify({ error: 'HTTP ' + status, body });
}

const raw = String(items[0].json.output ?? '').trim();

function dedupeReply(text) {
  if (!text) return text;
  const half = Math.floor(text.length / 2);
  if (text.length > 30) {
    const left = text.slice(0, half).trim();
    const right = text.slice(half).trim();
    if (left === right) return left;
  }
  const parts = text.split(/\n+/).map((p) => p.trim()).filter(Boolean);
  const unique = [];
  for (const p of parts) {
    if (unique[unique.length - 1] !== p) unique.push(p);
  }
  return unique.join('\n');
}

return [{ json: { output: dedupeReply(raw) } }];
